/**
 * Hand-curated Supabase Database type for b1n0.
 *
 * NOTE: This file is *not* generated by `supabase gen types typescript`.
 * That CLI requires a project-id + DB connection that lives outside
 * this repo, so we maintain this file by hand. When you add a new
 * column or RPC, update this file in the same PR — `npm run build`
 * will catch you if your code disagrees with the schema.
 *
 * Coverage goals:
 *   ▸ Every table the admin panels read or write.
 *   ▸ Every RPC called from the client.
 *   ▸ The shapes are accurate enough for `createClient<Database>()`
 *     to drive .from('x').select(...) and .rpc('y', {...}) typing.
 *
 * Keep it accurate, not exhaustive. Use `Json` for free-form fields.
 */

export type Json =
  | string
  | number
  | boolean
  | null
  | { [key: string]: Json | undefined }
  | Json[]

// ── Row shapes ────────────────────────────────────────────────

export interface ProfileRow {
  id: string
  name: string | null
  username: string | null
  first_name: string | null
  last_name: string | null
  dob: string | null
  phone: string | null
  phone_country_code: string | null
  address_line1: string | null
  address_line2: string | null
  city: string | null
  state: string | null
  country: string | null
  balance: number
  tier: 1 | 2 | 3
  currency: string
  total_predictions: number
  correct_predictions: number
  total_cobrado: number
  role: string | null
  is_admin: boolean
  must_change_password: boolean
  avatar_url: string | null
  notification_prefs: Json | null
  created_at: string
}

