// ── RPC shapes ────────────────────────────────────────────────

export interface CheckAdminStatusReturn {
  is_admin: boolean
  authenticated: boolean
  user_id?: string
  checked_at?: string
}

export interface AdminAdjustBalanceReturn {
  ok?: boolean
  error?: string
  new_balance?: number
}

export interface SweepToTreasuryReturn {
  ok?: boolean
  error?: string
  swept_total: number
  tx_count: number
}

export interface ExecutePurchaseReturn {
  position_id?: string
  contracts?: number
  price_at_purchase?: number
  payout_if_win?: number
  fee_paid?: number
  gross_amount?: number
  tx_fee_rate?: number
  yes_price_new?: number
  no_price_new?: number
  pool_remaining?: number
  error?: string
}

// ── Database — the shape Supabase expects ─────────────────────

type NoArgs = Record<string, never>

// Permissive insert/update shapes. Real defaults live in the DB schema;
// the supabase-js generic only needs *something* shaped like a record.
// Tighten per-table later if you want stricter inserts.
type InsertOptional = Record<string, unknown>
type UpdateOptional = Record<string, unknown>

type Table<Row extends object> = {
  Row: Row
  Insert: InsertOptional
  Update: UpdateOptional
  Relationships: []
}

export interface Database {
  public: {
    Tables: {
      profiles: Table<ProfileRow>
      events: Table<EventRow>
      event_markets: Table<EventMarketRow>
      positions: Table<PositionRow>
      predictions: Table<PredictionRow>
      market_transactions: Table<MarketTransactionRow>
      balance_ledger: Table<BalanceLedgerRow>
      platform_config: Table<PlatformConfigRow>
      platform_ledger: Table<PlatformLedgerRow>
      rate_limits: Table<RateLimitRow>
      lp_deposits: Table<LpDepositRow>
      comments: Table<CommentRow>
      notifications: Table<NotificationRow>
      friendships: Table<FriendshipRow>
    }
    Views: Record<string, never>
    Functions: {
      check_admin_status: {
        Args: NoArgs
        Returns: CheckAdminStatusReturn
      }
      is_admin: {
        Args: { user_id: string }
        Returns: boolean
      }
      admin_adjust_balance: {
        Args: { p_user_id: string; p_amount: number; p_reason?: string }
        Returns: AdminAdjustBalanceReturn
      }
      admin_reset_password: {
        Args: { p_user_id: string; p_new_password: string }
        Returns: { ok?: boolean; error?: string }
      }
      reset_user_password: {
        Args: { p_email: string }
        Returns: { ok?: boolean; temp?: string; error?: string }
      }
      sweep_to_treasury: {
        Args: NoArgs
        Returns: SweepToTreasuryReturn
      }
      update_platform_config: {
        Args: { p_key: string; p_value: number }
        Returns: void
      }
      settle_event: {
        Args: { p_event_id: string; p_result: string }
        Returns: Json
      }
      settle_predictions: {
        Args: { p_event_id: string; p_result: string }
        Returns: Json
      }
      initialize_market: {
        Args: {
          p_event_id: string
          p_pool_total?: number
          p_initial_yes_pct?: number
          p_spread_enabled?: boolean
          p_synthetic_shares?: number
          p_sponsor_amount?: number | null
          p_lp_return_pct?: number
          p_launch_mode?: string
        }
        Returns: EventMarketRow
      }
      initialize_option_markets: {
        Args: { p_event_id: string }
        Returns: Json
      }
      deposit_lp_capital: {
        Args: {
          p_event_id: string
          p_user_id: string
          p_amount: number
          p_return_pct?: number
        }
        Returns: Json
      }
      execute_purchase: {
        Args: { p_event_id: string; p_user_id: string; p_side: string; p_gross: number }
        Returns: ExecutePurchaseReturn
      }
      preview_purchase: {
        Args: { p_event_id: string; p_user_id: string; p_side: string; p_gross: number }
        Returns: Json
      }
      execute_sell: {
        Args: { p_position_id: string; p_user_id: string; p_contracts?: number }
        Returns: Json
      }
      execute_option_purchase: {
        Args: { p_event_id: string; p_user_id: string; p_option: string; p_gross: number }
        Returns: Json
      }
      preview_option_purchase: {
        Args: { p_event_id: string; p_user_id: string; p_option: string; p_gross: number }
        Returns: Json
      }
      cast_vote: {
        Args: { p_event_id: string; p_user_id: string; p_side: string; p_amount: number }
        Returns: Json
      }
      deposit_balance: {
        Args: { p_amount: number; p_label?: string }
        Returns: Json
      }
      withdraw_balance: {
        Args: { p_amount: number; p_method?: string }
        Returns: Json
      }
      check_rate_limit: {
        Args: { p_action: string; p_window_seconds?: number; p_max?: number }
        Returns: boolean
      }
      record_rate_limit: {
        Args: { p_action: string }
        Returns: void
      }
    }
    Enums: Record<string, never>
    CompositeTypes: Record<string, never>
  }
}
